// ============================================
// SZUKAJ DOPASOWANIA W BAZIE WIEDZY
// ============================================

const emailData = $('📊 Parsuj Odpowiedź AI').first().json;
const sheetsData = $('📊 Google Sheets — Baza Wiedzy').all();

const pytanie = (emailData.subject + ' ' + emailData.bodyClean).toLowerCase();

// Prosta wyszukiwarka przez słowa kluczowe
let bestMatch = null;
let bestScore = 0;

for (const row of sheetsData) {
  const kluczowe = (row.json.Slowa_kluczowe || '').toLowerCase();
  const kategoria = (row.json.Kategoria || '').toLowerCase();
  const odpowiedz = row.json.Odpowiedz || '';

  if (!odpowiedz) continue;

  // Policz trafienia
  const keywords = kluczowe.split(',').map(k => k.trim());
  let score = 0;
  for (const kw of keywords) {
    if (kw && pytanie.includes(kw)) score++;
  }

  if (score > bestScore) {
    bestScore = score;
    bestMatch = {
      kategoria: row.json.Kategoria,
      pytanieTyp: row.json.Pytanie_typ,
      odpowiedz: odpowiedz,
      score: score,
      zrodlo: row.json.Zrodlo || 'baza wiedzy'
    };
  }
}

const znaleziono = bestScore > 0;

return [{
  json: {
    ...emailData,
    bazaWiedzyZnaleziono: znaleziono,
    bazaWiedzyOdpowiedz: bestMatch?.odpowiedz || null,
    bazaWiedzyKategoria: bestMatch?.kategoria || null,
    bazaWiedzyScore: bestScore,
    bazaWiedzyZrodlo: bestMatch?.zrodlo || null,
    processingStatus: 'knowledge_searched'
  }
}];

// ============================================
// GLOBALNY ERROR HANDLER
// ============================================

const errorData = $input.first().json;
const errorMsg = errorData.error?.message || JSON.stringify(errorData);

console.error('Workflow Error:', errorMsg);

return [{
  json: {
    error: true,
    errorMessage: errorMsg,
    timestamp: new Date().toISOString(),
    workflowStep: 'unknown'
  }
}];

