// Pobierz email nadawcy z wcześniejszego węzła
const senderEmail = $('Parsuj odpowiedz AI').item.json.mail_wysylki ?? '';
const senderDomain = $('Parsuj odpowiedz AI').item.json.klient_domena ?? '';
const subject = $('Gmail Trigger').item.json.Subject ?? '';

// Pobierz wszystkie taski
const tasks = $input.item.json.tasks ?? [];

// ID pola email w ClickUp (z Twojego workflow)
const EMAIL_FIELD_ID = 'eb65134e-d02b-45cd-94b0-6faad6e613a3';

// Szukaj taska po emailu
let foundTask = null;
let matchMethod = null;

for (const task of tasks) {
  const fields = task.custom_fields ?? [];

  // Szukaj po dokładnym emailu
  const emailField = fields.find(f => f.id === EMAIL_FIELD_ID);
  const taskEmail = emailField?.value ?? '';

  if (taskEmail && senderEmail && taskEmail.toLowerCase() === senderEmail.toLowerCase()) {
    foundTask = task;
    matchMethod = 'email_exact';
    break;
  }

  // Fallback - szukaj po domenie
  if (!foundTask && senderDomain && taskEmail.includes(senderDomain)) {
    foundTask = task;
    matchMethod = 'domain_match';
  }

  // Fallback - szukaj po temacie maila (usuń Re:/Odp:)
  const cleanSubject = subject.replace(/^(Re:|Odp:|Fwd:|Fw:)\s*/gi, '').trim().toLowerCase();
  const taskName = (task.name ?? '').toLowerCase();

  if (!foundTask && cleanSubject && taskName.includes(cleanSubject.substring(0, 30))) {
    foundTask = task;
    matchMethod = 'subject_match';
  }
}

// Zwróć wynik
if (foundTask) {
  return {
    json: {
      found: true,
      match_method: matchMethod,
      task_id: foundTask.id,
      task_name: foundTask.name,
      task_status: foundTask.status?.status ?? 'brak statusu',
      task_status_color: foundTask.status?.color ?? '',
      task_url: foundTask.url ?? '',
      task_assignees: (foundTask.assignees ?? []).map(a => a.username).join(', '),
      task_date_created: foundTask.date_created ?? null,
      task_date_updated: foundTask.date_updated ?? null,
      task_custom_fields: foundTask.custom_fields ?? [],
      sender_email: senderEmail,
      sender_domain: senderDomain
    }
  };
} else {
  return {
    json: {
      found: false,
      match_method: null,
      task_id: null,
      task_name: null,
      task_status: null,
      task_url: null,
      sender_email: senderEmail,
      sender_domain: senderDomain
    }
  };
}

