parameters.jsCode:
const raw = item.json.message?.content || item.json.content || item.json.text || "";

// 1. usuń markdown ``` ```
let cleaned = raw
  .replace(/```json\s*/gi, '')
  .replace(/```/g, '')
  .trim();

// 2. spróbuj znaleźć JSON w środku (najważniejsze!)
const match = cleaned.match(/\{[\s\S]*\}/);

let parsed;

if (match) {
  try {
    parsed = JSON.parse(match[0]);
  } catch (e) {
    parsed = {
      error: "JSON parse failed",
      extracted: match[0],
      original: raw
    };
  }
} else {
  parsed = {
    error: "No JSON found",
    original: raw
  };
}

return { json: parsed };

// ============================================
// WYCIĄGNIJ DANE Z TASKA CLICKUP
// ============================================

const task = item.json;

// Pomocnicza funkcja do pobierania custom field po nazwie lub ID
function getField(task, nameOrId) {
  const fields = task.custom_fields || [];
  const field = fields.find(f => 
    f.name?.toLowerCase() === nameOrId.toLowerCase() || 
    f.id === nameOrId
  );
  if (!field) return '';

  // Obsługa różnych typów pól
  if (field.value !== undefined && field.value !== null) {
    if (typeof field.value === 'object' && field.value.username) {
      return field.value.username;
    }
    return String(field.value);
  }
  return '';
}

// Wyciągnij dane
const taskId = task.id || '';
const taskName = task.name || 'Brak nazwy';
const taskDescription = task.description || task.text_content || 'Brak opisu';
const taskStatus = task.status?.status || '';
const taskUrl = task.url || '';

// Custom fields - dostosuj nazwy do swoich pól w ClickUp
const klientEmail = getField(task, 'email') || 
                    getField(task, 'mail_wysylki') || 
                    getField(task, 'eb65134e-d02b-45cd-94b0-6faad6e613a3') || '';

const klientImie = getField(task, 'klient') || 
                   getField(task, 'imie_nazwisko') || 
                   getField(task, 'klient_imie_nazwisko') || 
                   getField(task, '623f589b-4ded-47e5-ae3f-4ed3dd63c11c') || '';

const cena = getField(task, 'cena') || 
             getField(task, 'price') || 
             getField(task, 'kwota') || 
             getField(task, 'budget') || '';

const terminRealizacji = getField(task, 'termin') || 
                         getField(task, 'deadline') || 
                         getField(task, 'data_realizacji') || '';

const nazwaFirmy = getField(task, 'firma') || 
                   getField(task, 'nazwa_firmy') || 
                   getField(task, '8132fc0e-6bf7-40b6-84fc-72c9415fb6ab') || '';

const zakresUslug = getField(task, 'zakres') || 
                    getField(task, 'uslugi') || 
                    getField(task, 'opis_projektu') || 
                    taskDescription || '';

// Assignees
const assignees = (task.assignees || []).map(a => a.username || a.email || '').join(', ');

// Walidacja - czy mamy email klienta?
if (!klientEmail) {
  return {
    json: {
      error: true,
      errorMessage: 'Brak emaila klienta w tasku: ' + taskId,
      taskId,
      taskName
    }
  };
}

return {
  json: {
    error: false,
    taskId,
    taskName,
    taskDescription,
    taskStatus,
    taskUrl,
    klientEmail,
    klientImie: klientImie || 'Kliencie',
    cena: cena || 'Do ustalenia',
    terminRealizacji: terminRealizacji || 'Do uzgodnienia',
    nazwaFirmy: nazwaFirmy || '',
    zakresUslug,
    assignees,
    customFields: task.custom_fields || [],
    timestamp: new Date().toISOString()
  }
};

// Połącz dane taska z wygenerowaną treścią maila
const taskData = $('🔧 Wyciągnij Dane z Taska').item.json;
const aiContent = item.json.message?.content || item.json.content || '';

return {
  json: {
    ...taskData,
    emailBody: aiContent,
    emailSubject: `Oferta do akceptacji: ${taskData.taskName}`,
    emailTo: taskData.klientEmail,
    emailToName: taskData.klientImie
  }
};

