const now = new Date();

const primaryStart = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const primaryEnd   = new Date(now.getFullYear(), now.getMonth(), 0);
const compareStart = new Date(now.getFullYear(), now.getMonth() - 2, 1);
const compareEnd   = new Date(now.getFullYear(), now.getMonth() - 1, 0);

function fmt(d) {
  return d.toISOString().split('T')[0];
}

const monthLabel = primaryStart.toLocaleDateString('en-GB', {
  month: 'long',
  year: 'numeric'
});

console.log('[DatePrep] Period: ' + fmt(primaryStart) + ' to ' + fmt(primaryEnd));

return [{
  json: {
    startDate:       fmt(primaryStart),
    endDate:         fmt(primaryEnd),
    compareStart:    fmt(compareStart),
    compareEnd:      fmt(compareEnd),
    startTs:         primaryStart.getTime(),
    endTs:           primaryEnd.getTime(),
    monthLabel:      monthLabel,
    monthShort:      primaryStart.toLocaleDateString('en-GB', { month: '2-digit', year: 'numeric' }),
    reportTitle:     'Monthly Report ' + monthLabel,
    generatedAt:     now.toISOString(),
    metaTimeRange:   JSON.stringify({ since: fmt(primaryStart), until: fmt(primaryEnd) }),
    gaqlStart:       fmt(primaryStart),
    gaqlEnd:         fmt(primaryEnd),
    bingStart:       fmt(primaryStart),
    bingEnd:         fmt(primaryEnd),
    metricoolStart:  fmt(primaryStart),
    metricoolEnd:    fmt(primaryEnd)
  }
}];

const CLIENT_REGISTRY = [
  {
    clientId:   'client_001',
    clientName: 'Acme E-Commerce',
    owner:      'Manager A',
    currency:   'PLN',
    timezone:   'Europe/Warsaw',
    active:     true,
    tags:       ['ecommerce'],
    platforms: {
      googleAds: {
        enabled:         true,
        customerId:      '111-222-3333',
        loginCustomerId: 'ADMIN_MCC_ID'
      },
      googleAnalytics: {
        enabled:    true,
        propertyId: 'properties/111111111'
      },
      metaAds: {
        enabled:   true,
        accountId: 'act_111111111111'
      },
      bingAds: {
        enabled:    true,
        accountId:  '11111111',
        customerId: '11111111'
      },
      metricool: {
        enabled: true,
        brandId: 'metricool_brand_001'
      }
    }
  },
  {
    clientId:   'client_002',
