];

const clientIds = CLIENT_REGISTRY.map(function(c) { return c.clientId; });
const uniqueIds = new Set(clientIds);
if (uniqueIds.size !== clientIds.length) {
  throw new Error('[ClientRegistry] DUPLICATE clientId detected!');
}

const accountIdIndex = {};
for (const client of CLIENT_REGISTRY) {
  for (const platKey of Object.keys(client.platforms)) {
    const config = client.platforms[platKey];
    const aid = config.accountId || config.customerId || config.propertyId || config.brandId;
    if (aid) {
      if (accountIdIndex[aid]) {
        throw new Error('[ClientRegistry] Account ID ' + aid + ' assigned to multiple clients!');
      }
      accountIdIndex[aid] = client.clientId;
    }
  }
}

const activeClients = CLIENT_REGISTRY.filter(function(c) { return c.active; });

console.log('[ClientRegistry] Active clients: ' + activeClients.length);

return activeClients.map(function(client) {
  return {
    json: Object.assign({}, client, {
      registryVersion: '2.0',
      accountIdIndex:  accountIdIndex,
      totalClients:    activeClients.length
    })
  };
});

const clientMeta = $('Split Per Client1').first().json;
const aid = clientMeta.platforms.googleAds.accountId || '';
return [{ json: { _skip: !clientMeta.platforms.googleAds.enabled, _reason: 'Google Ads disabled for this client', clientId: clientMeta.clientId } }];

