return [{ json: Object.assign({}, item, { _source: 'metaDemographics', _clientId: clientId }) }];

const item = $input.first().json;
const clientId = $('Split Per Client1').first().json.clientId;
return [{ json: Object.assign({}, item, { _source: 'metricool', _clientId: clientId }) }];

var clientMeta = $('Split Per Client1').first().json;
var dates      = $('Date Preparation1').first().json;
var allItems   = $input.all();

var CLIENT_ID   = clientMeta.clientId;
var CLIENT_NAME = clientMeta.clientName;
var CLIENT_OWNER = clientMeta.owner;
var PLATFORMS   = clientMeta.platforms;

console.log('[Aggregation] Client: ' + CLIENT_NAME + ' (' + CLIENT_ID + ')');

function safeInt(v)   { return parseInt(v)   || 0; }
function safeFloat(v) { return parseFloat(v) || 0; }
function pct(n, d)    { return d > 0 ? ((n / d) * 100).toFixed(2) : '0.00'; }
function divf(n, d)   { return d > 0 ? (n / d).toFixed(2) : '0.00'; }

function getAction(actions, type) {
  if (!Array.isArray(actions)) return 0;
  var found = actions.find(function(a) { return a.action_type === type; });
  return found ? safeFloat(found.value) : 0;
}

function findBySource(src) {
  return allItems.filter(function(i) { return i.json._source === src; });
}

var googleAdsItems   = findBySource('googleAds');
var gaItems          = findBySource('googleAnalytics');
var bingItems        = findBySource('bingAds');
var metaCampItems    = findBySource('metaCampaigns');
var metaPlatItems    = findBySource('metaPlatforms');
var metaDemoItems    = findBySource('metaDemographics');
var metricoolItems   = findBySource('metricool');

var googleAds = null;
if (PLATFORMS.googleAds.enabled && googleAdsItems.length > 0) {
  var rawGA = googleAdsItems[0].json;
  var results = rawGA.results || [];
  var totalClicks = 0, totalImpressions = 0, totalCostMicros = 0;
  var totalConversions = 0, totalConversionValue = 0;
  var campaigns = [];

  for (var i = 0; i < results.length; i++) {
    var result = results[i];
    var m = result.metrics  || {};
    var c = result.campaign || {};
    var clicks      = safeInt(m.clicks);
    var impressions = safeInt(m.impressions);
    var costMicros  = safeInt(m.cost_micros || m.costMicros);
    var conversions = safeFloat(m.conversions);
    var convValue   = safeFloat(m.conversions_value || m.conversionsValue);
    totalClicks          += clicks;
    totalImpressions     += impressions;
    totalCostMicros      += costMicros;
    totalConversions     += conversions;
    totalConversionValue += convValue;
    if (c.name) {
      campaigns.push({
        clientId:    CLIENT_ID,
        clientName:  CLIENT_NAME,
        platform:    'google_ads',
        id:          c.id,
        name:        c.name,
        status:      c.status,
        type:        c.advertising_channel_type,
        clicks:      clicks,
        impressions: impressions,
        cost:        (costMicros / 1000000).toFixed(2),
        ctr:         pct(clicks, impressions),
        avgCpc:      divf(costMicros / 1000000, clicks),
        conversions: Math.round(conversions),
        convValue:   convValue.toFixed(2),
        roas:        costMicros > 0 ? (convValue / (costMicros / 1000000)).toFixed(2) : '0.00'
      });
    }
  }

  var totalCost = totalCostMicros / 1000000;
  googleAds = {
    clientId:    CLIENT_ID,
    clientName:  CLIENT_NAME,
    owner:       CLIENT_OWNER,
    platform:    'google_ads',
    totalClicks:         totalClicks,
    totalImpressions:    totalImpressions,
    totalCost:           totalCost.toFixed(2),
    totalConversions:    Math.round(totalConversions),
    totalConversionValue: totalConversionValue.toFixed(2),
    avgCTR:              pct(totalClicks, totalImpressions),
    avgCPC:              divf(totalCost, totalClicks),
    ROAS:                divf(totalConversionValue, totalCost),
    CPA:                 divf(totalCost, totalConversions),
    activeCampaigns:     campaigns.length,
    topCampaigns:        campaigns.sort(function(a, b) { return parseFloat(b.cost) - parseFloat(a.cost); }).slice(0, 10)
  };
  console.log('[GoogleAds][' + CLIENT_ID + '] Campaigns: ' + campaigns.length + ', Cost: ' + totalCost.toFixed(2));
}

var googleAnalytics = null;
if (PLATFORMS.googleAnalytics.enabled && gaItems.length > 0) {
  var totalSessions = 0, totalUsers = 0, totalNewUsers = 0;
  var totalPageViews = 0, gaConversions = 0, totalRevenue = 0;
  var bounceRates = [], sessionDurations = [];
  var sourceMap = {}, deviceMap = {};

  for (var j = 0; j < gaItems.length; j++) {
    var d = gaItems[j].json;
    var sessions    = safeInt(d.sessions);
    var users       = safeInt(d.totalUsers);
    var newUsers    = safeInt(d.newUsers);
    var pageViews   = safeInt(d.screenPageViews);
    var conv        = safeInt(d.conversions);
    var revenue     = safeFloat(d.totalRevenue);
    var bounce      = safeFloat(d.bounceRate);
    var duration    = safeFloat(d.averageSessionDuration);
    totalSessions    += sessions;
    totalUsers       += users;
    totalNewUsers    += newUsers;
    totalPageViews   += pageViews;
    gaConversions    += conv;
    totalRevenue     += revenue;
    if (bounce > 0)   bounceRates.push(bounce);
    if (duration > 0) sessionDurations.push(duration);
    var srcKey = (d.sessionSource || 'unknown') + ' / ' + (d.sessionMedium || 'unknown');
    sourceMap[srcKey] = (sourceMap[srcKey] || 0) + sessions;
    var dev = d.deviceCategory || 'unknown';
    deviceMap[dev] = (deviceMap[dev] || 0) + sessions;
  }

  var avgBounce   = bounceRates.length > 0 ? bounceRates.reduce(function(a, b) { return a + b; }, 0) / bounceRates.length : 0;
  var avgDuration = sessionDurations.length > 0 ? sessionDurations.reduce(function(a, b) { return a + b; }, 0) / sessionDurations.length : 0;
  var topSources  = Object.entries(sourceMap).sort(function(a, b) { return b[1] - a[1]; }).slice(0, 5).map(function(e) { return { source: e[0], sessions: e[1] }; });

  googleAnalytics = {
    clientId:    CLIENT_ID,
    clientName:  CLIENT_NAME,
    owner:       CLIENT_OWNER,
    platform:    'google_analytics',
    totalSessions:         totalSessions,
    totalUsers:            totalUsers,
    totalNewUsers:         totalNewUsers,
    returningUsers:        totalUsers - totalNewUsers,
    totalPageViews:        totalPageViews,
    totalConversions:      gaConversions,
    totalRevenue:          totalRevenue.toFixed(2),
    avgBounceRate:         avgBounce.toFixed(2),
    avgSessionDurationSec: Math.round(avgDuration),
    avgSessionDurationStr: Math.floor(avgDuration / 60) + 'm ' + Math.round(avgDuration % 60) + 's',
    pagesPerSession:       divf(totalPageViews, totalSessions),
    conversionRate:        pct(gaConversions, totalSessions),
    topSources:            topSources,
    deviceBreakdown:       deviceMap
  };
  console.log('[GA4][' + CLIENT_ID + '] Sessions: ' + totalSessions + ', Revenue: ' + totalRevenue.toFixed(2));
}

var bingAds = null;
if (PLATFORMS.bingAds.enabled && bingItems.length > 0) {
  var rawBing = bingItems[0].json;
  var bingRows = rawBing.rows || rawBing.Rows || [];
  var bTotalClicks = 0, bTotalImpressions = 0, bTotalSpend = 0;
  var bTotalConv = 0, bTotalRevenue = 0;
  var bCampaigns = [];

  for (var k = 0; k < bingRows.length; k++) {
    var row = bingRows[k];
    var bc  = safeInt(row.Clicks || row.clicks);
    var bi  = safeInt(row.Impressions || row.impressions);
    var bs  = safeFloat(row.Spend || row.spend);
    var bco = safeFloat(row.Conversions || row.conversions);
    var br  = safeFloat(row.Revenue || row.revenue);
    bTotalClicks      += bc;
    bTotalImpressions += bi;
    bTotalSpend       += bs;
    bTotalConv        += bco;
    bTotalRevenue     += br;
    bCampaigns.push({
      clientId:    CLIENT_ID,
      clientName:  CLIENT_NAME,
      platform:    'bing_ads',
      name:        row.CampaignName || row.campaignName || 'Unknown',
      status:      row.CampaignStatus || 'Unknown',
      clicks:      bc,
      impressions: bi,
      spend:       bs.toFixed(2),
      ctr:         pct(bc, bi),
      cpc:         divf(bs, bc),
      conversions: Math.round(bco),
      revenue:     br.toFixed(2),
      roas:        divf(br, bs)
    });
  }

  bingAds = {
    clientId:    CLIENT_ID,
    clientName:  CLIENT_NAME,
    owner:       CLIENT_OWNER,
    platform:    'bing_ads',
    totalClicks:      bTotalClicks,
    totalImpressions: bTotalImpressions,
    totalSpend:       bTotalSpend.toFixed(2),
    totalConversions: Math.round(bTotalConv),
    totalRevenue:     bTotalRevenue.toFixed(2),
    avgCTR:           pct(bTotalClicks, bTotalImpressions),
    avgCPC:           divf(bTotalSpend, bTotalClicks),
    ROAS:             divf(bTotalRevenue, bTotalSpend),
    CPA:              divf(bTotalSpend, bTotalConv),
    activeCampaigns:  bCampaigns.length,
    campaigns:        bCampaigns
  };
  console.log('[Bing][' + CLIENT_ID + '] Campaigns: ' + bCampaigns.length + ', Spend: ' + bTotalSpend.toFixed(2));
}

var metaAds = null;
if (PLATFORMS.metaAds.enabled && metaCampItems.length > 0) {
  var rawMeta    = metaCampItems[0].json;
  var metaRows   = rawMeta.data || [];
  var mSpend = 0, mImpressions = 0, mClicks = 0, mReach = 0;
  var mPurchases = 0, mPurchaseValue = 0, mLeads = 0;
  var mVideoViews = 0, mAddToCart = 0, mInitCheckout = 0, mLandingViews = 0;
  var mCampaigns = [];

  for (var mc = 0; mc < metaRows.length; mc++) {
    var mr = metaRows[mc];
    var spend       = safeFloat(mr.spend);
    var impressions = safeInt(mr.impressions);
    var clicks      = safeInt(mr.clicks);
    var reach       = safeInt(mr.reach);
    var actions     = mr.actions       || [];
    var actionVals  = mr.action_values || [];
    var purchases     = getAction(actions,    'purchase');
    var purchaseValue = getAction(actionVals, 'purchase');
    var leads         = getAction(actions,    'lead');
    var linkClicks    = getAction(actions,    'link_click');
    var videoViews    = getAction(actions,    'video_view');
    var addToCart     = getAction(actions,    'add_to_cart');
    var initCheckout  = getAction(actions,    'initiate_checkout');
    var landingViews  = getAction(actions,    'landing_page_view');
    mSpend         += spend;
    mImpressions   += impressions;
    mClicks        += clicks;
    mReach         += reach;
    mPurchases     += purchases;
    mPurchaseValue += purchaseValue;
    mLeads         += leads;
    mVideoViews    += videoViews;
    mAddToCart     += addToCart;
    mInitCheckout  += initCheckout;
    mLandingViews  += landingViews;
    mCampaigns.push({
      clientId:      CLIENT_ID,
      clientName:    CLIENT_NAME,
      platform:      'meta_ads',
      id:            mr.campaign_id,
      name:          mr.campaign_name,
      objective:     mr.objective,
      spend:         spend.toFixed(2),
      impressions:   impressions,
      clicks:        clicks,
      reach:         reach,
      purchases:     Math.round(purchases),
      purchaseValue: purchaseValue.toFixed(2),
      leads:         Math.round(leads),
      videoViews:    Math.round(videoViews),
      addToCart:     Math.round(addToCart),
      ctr:           pct(clicks, impressions),
      cpc:           divf(spend, clicks),
      cpm:           impressions > 0 ? ((spend / impressions) * 1000).toFixed(2) : '0.00',
      roas:          divf(purchaseValue, spend),
      cpa:           divf(spend, purchases + leads)
    });
  }

  var rawPlatforms = metaPlatItems.length > 0 ? (metaPlatItems[0].json.data || []) : [];
  var platformMap  = {};
  for (var mp = 0; mp < rawPlatforms.length; mp++) {
    var pr   = rawPlatforms[mp];
    var pkey = (pr.publisher_platform || 'unknown') + '_' + (pr.device_platform || 'unknown');
    if (!platformMap[pkey]) {
      platformMap[pkey] = { platform: pr.publisher_platform || 'unknown', device: pr.device_platform || 'unknown', spend: 0, impressions: 0, clicks: 0, reach: 0, purchases: 0, leads: 0 };
    }
    platformMap[pkey].spend       += safeFloat(pr.spend);
    platformMap[pkey].impressions += safeInt(pr.impressions);
    platformMap[pkey].clicks      += safeInt(pr.clicks);
    platformMap[pkey].reach       += safeInt(pr.reach);
    platformMap[pkey].purchases   += getAction(pr.actions || [], 'purchase');
    platformMap[pkey].leads       += getAction(pr.actions || [], 'lead');
  }
