  });
});

var rankBySpend       = clientDetails.slice().sort(function(a, b) { return parseFloat(b.totalSpend)       - parseFloat(a.totalSpend); });
var rankByROAS        = clientDetails.filter(function(c) { return parseFloat(c.blendedROAS) > 0; }).sort(function(a, b) { return parseFloat(b.blendedROAS) - parseFloat(a.blendedROAS); });
var rankByConversions = clientDetails.slice().sort(function(a, b) { return b.totalConversions             - a.totalConversions; });

var alerts = [];
for (var ai = 0; ai < clientDetails.length; ai++) {
  var c = clientDetails[ai];
  if (parseFloat(c.blendedROAS) > 0 && parseFloat(c.blendedROAS) < 1.0) {
    alerts.push({ level: 'HIGH', clientId: c.clientId, client: c.clientName, owner: c.owner, issue: 'Blended ROAS below 1.0 (' + c.blendedROAS + 'x) — spending more than earning' });
  }
  if (parseFloat(c.totalSpend) > 0 && c.totalConversions === 0) {
    alerts.push({ level: 'MEDIUM', clientId: c.clientId, client: c.clientName, owner: c.owner, issue: 'Zero conversions despite ' + c.totalSpend + ' spend' });
  }
  if ((c.activePlatforms || []).length === 0) {
    alerts.push({ level: 'LOW', clientId: c.clientId, client: c.clientName, owner: c.owner, issue: 'No active platforms detected' });
  }
}

var dates = $('Date Preparation1').first().json;

var adminReport = {
  reportType:   'ADMIN_GLOBAL_OVERVIEW',
  reportId:     'ADMIN_' + dates.startDate + '_' + dates.endDate,
  period: {
    start: dates.startDate,
    end:   dates.endDate,
    label: dates.monthLabel
  },
  generatedAt:  new Date().toISOString(),
  clientCount:  clientReports.length,
  clientIds:    clientDetails.map(function(c) { return c.clientId; }),
  grandTotals: {
    totalAdSpend:         grandTotalSpend.toFixed(2),
    totalConversions:     grandTotalConversions,
    totalConversionValue: grandTotalConvValue.toFixed(2),
    blendedROAS:          divf(grandTotalConvValue, grandTotalSpend),
    blendedCPA:           divf(grandTotalSpend, grandTotalConversions),
    totalWebSessions:     grandTotalSessions,
    totalPaidReach:       grandTotalReach,
    totalSocialFollowers: grandTotalFollowers,
    googleAdsSpend:       grandTotalGAds.toFixed(2),
    metaAdsSpend:         grandTotalMeta.toFixed(2),
    bingAdsSpend:         grandTotalBing.toFixed(2),
    googleAdsPct:         pctf(grandTotalGAds, grandTotalSpend),
    metaAdsPct:           pctf(grandTotalMeta, grandTotalSpend),
    bingAdsPct:           pctf(grandTotalBing, grandTotalSpend)
  },
  platformSummary: {
    googleAds: Object.assign({}, platformTotals.googleAds, {
      totalSpend: platformTotals.googleAds.spend.toFixed(2),
      avgCTR:     pctf(platformTotals.googleAds.clicks, platformTotals.googleAds.impressions)
    }),
    googleAnalytics: Object.assign({}, platformTotals.googleAnalytics, {
      totalRevenue: platformTotals.googleAnalytics.revenue.toFixed(2)
    }),
    bingAds: Object.assign({}, platformTotals.bingAds, {
      totalSpend: platformTotals.bingAds.spend.toFixed(2),
      avgCTR:     pctf(platformTotals.bingAds.clicks, platformTotals.bingAds.impressions)
    }),
    metaAds: Object.assign({}, platformTotals.metaAds, {
      totalSpend:     platformTotals.metaAds.spend.toFixed(2),
      totalConvValue: platformTotals.metaAds.convValue.toFixed(2),
      overallROAS:    divf(platformTotals.metaAds.convValue, platformTotals.metaAds.spend)
    }),
    metricool: platformTotals.metricool
  },
  clientDetails:  clientDetails,
  rankings: {
    bySpend:        rankBySpend,
    byROAS:         rankByROAS,
    byConversions:  rankByConversions
  },
  ownerBreakdown: ownerBreakdown,
  alerts: {
    count:  alerts.length,
    items:  alerts,
    high:   alerts.filter(function(a) { return a.level === 'HIGH';   }),
    medium: alerts.filter(function(a) { return a.level === 'MEDIUM'; }),
    low:    alerts.filter(function(a) { return a.level === 'LOW';    })
  }
};

console.log('[AdminAgg] Complete. Clients: ' + clientReports.length + ', Total Spend: ' + grandTotalSpend.toFixed(2) + ', Blended ROAS: ' + divf(grandTotalConvValue, grandTotalSpend) + 'x, Alerts: ' + alerts.length);

return [{ json: adminReport }];

var err = $input.first().json;
console.error('[GlobalError] ' + JSON.stringify(err));
return [{ json: { errorType: 'WORKFLOW_ERROR', message: (err && err.message) || 'Unknown error', timestamp: new Date().toISOString(), workflow: 'Multi-Client Marketing Aggregator' } }];

